#include<bits/stdc++.h>
using namespace std;
const int N=300010,M=1500010;
int a[100010];
bool vis[N];
int dis[N];
int head[N],to[M],nxt[M],val[M],cnt;
void add(int x,int y,int z=0)
{
    to[++cnt]=y;
    nxt[cnt]=head[x];
    head[x]=cnt;
    val[cnt]=z;
}
void spfa()
{
    memset(dis,0x8f,sizeof(dis));
    dis[1]=0;
    queue<int> q;
    q.push(1);
    vis[1]=1;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        vis[t]=0;
        for(int i=head[t];i;i=nxt[i])
        {
            int v=to[i];
            if(dis[v]<dis[t]+val[i])
            {
                dis[v]=dis[t]+val[i];
                if(!vis[v])
                {
                    vis[v]=1;
                    q.push(v);
                }
            }
        }
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        add(i,i+n,-a[i]);
        add(i+n,i+2*n,a[i]);
    }
    for(int i=1;i<=m;i++)
    {
        int x,y,z;
        scanf("%d%d%d",&x,&y,&z);
        add(x,y);
        add(x+n,y+n);
        add(x+2*n,y+2*n);
        if(z==2)
        {
            add(y,x);
            add(y+n,x+n);
            add(y+2*n,x+2*n);
        }
    }
    spfa();
    printf("%d",max(0,dis[3*n]));
    return 0;
}
